using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// BREAKING CHANGE (.NET 9): ValidateScopes is now enabled by default in Development.
// A singleton that resolves a scoped service from the root provider will throw
// InvalidOperationException at startup. Fix: make CacheService scoped too.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// BREAKING CHANGE (.NET 9): HttpClientFactory now uses SocketsHttpHandler as the
// default primary handler. Casting to HttpClientHandler throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler with the new default handler type.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// BREAKING CHANGE (.NET 9): ForwardedHeadersMiddleware now ignores X-Forwarded-*
// headers from proxies not in KnownProxies or KnownNetworks.
// Fix: register trusted proxy addresses.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual reverse proxy address(es)
    options.KnownProxies.Add(IPAddress.Parse("10.0.0.1"));
});

// BREAKING CHANGE (.NET 9): HttpClientFactory Trace-level logs now redact all header
// values by default. Allowlist specific non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "X-Request-Id"
        && header != "X-Correlation-Id"
        && header != "Cache-Control"
        && header != "Accept"
        && header != "Content-Type"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

